/**
 * E2E Test: Health Check & Navigation
 * Verifica que a aplicação está acessível e rotas básicas funcionam
 */

import { test, expect } from '@playwright/test';

test.describe('App Health', () => {
  test('API health endpoint responds', async ({ request }) => {
    const response = await request.get('/api/health');
    // Pode ser 200 ou 404 dependendo se a rota existe
    expect([200, 404]).toContain(response.status());
  });

  test('Render start API responds', async ({ request }) => {
    const response = await request.get('/api/render/start?action=video-test');
    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body.success).toBe(true);
  });
});

test.describe('Navigation', () => {
  test('home page loads', async ({ page }) => {
    const response = await page.goto('/');
    // Should load without server error
    expect(response?.status()).toBeLessThan(500);
  });

  test('login page accessible', async ({ page }) => {
    const response = await page.goto('/login');
    expect(response?.status()).toBeLessThan(500);
  });
});
